      "expectation_id": "提醒查阅具体保险合同",
      "status": "fulfilled",
      "reason": "回答结尾建议“查阅您的保险合同条款获取准确信息”"
    },
    {
      "expectation_id": "提及轻症分组限制",
      "status": "not_fulfilled",
      "reason": "回答中未提及任何与分组限制相关的信息"
    },
    {
      "expectation_id": "说明轻症赔付对重疾保额的影响",
      "status": "not_fulfilled",
      "reason": "回答中未说明轻症赔付后重疾保额是否变化"
    },
    {
      "expectation_id": "说明累计赔付上限限制",
      "status": "not_fulfilled",
      "reason": "回答中未提及累计赔付上限"
    }
  ],
  "overall_fulfillment": {
    "status": "fulfilled",
