    "non_blocking_gaps": [
      "轻症分组限制",
      "轻症赔付对重疾保额的影响",
      "累计赔付上限限制"
    ]
  },
  "expected": {
    "key_points": [
      "轻症可以多次赔付",
      "每次赔付比例为20%-30%",
      "有次数上限（如3或5次）",
      "存在间隔期要求",
      "需查阅合同"
    ]
  },
  "missing": [
    {
      "expectation_id": "提及轻症分组限制",
      "detail": "未提及同一组别轻症只能赔付一次"
    },
    {
      "expectation_id": "说明轻症赔付对重疾保额的影响",
      "detail": "未说明部分产品轻症赔付后重疾保额不变或减少"
    },
    {
      "expectation_id": "说明累计赔付上限限制",
      "detail": "未说明累计赔付上限可能有限制"
    }
  ],
  "wrong": [],
  "extra": [],
  "evidence": [
    {
      "source": "gold_answer",
      "content": "轻症可以多次赔付，具体次数以合同约定为准（常见为3-5次）。每次确诊的轻症需满足合同定义的疾病标准，且两次轻症确诊之间通常有间隔期（如90天或180天）。每次轻症赔付的金额一般为基本保额的一定比例，常见比例为20%-30%。"
    }
  ],
  "semantic_equivalence_checks": [],
  "needs_human_review": false,
  "quality_flags": [
    "信息覆盖不完整（缺少分组、保额影响等补充性细节）"
  ],
  "intent_model": {
    "primary_question": "轻症是否可多次赔付，每次赔多少",
    "expected_answer_type": "事实性解释 + 建议查合同"
  },
  "consumer_contract": {},
  "reference_generation_basis": {
    "gold_answer_summary": "轻症可多次赔付（常见3-5次），每次赔付基本保额的20%-30%，有间隔期，可能存在分组和累计上限，具体以合同为准。"
  },
  "verdict_derivation": {
    "score_dimensions": {
      "correctness": 1.0,
      "completeness": 0.6,
      "clarity": 1.0
    }
  },
  "boundary_decision": {
    "within_evaluable_scope": true,
    "uncontrollable_limits": [],
